tool_input.new_string:
// scoreRoundFactor controls the precision for score rounding (4 decimal places).
const scoreRoundFactor = 10000

// RoundScore rounds a float64 to 4 decimal places.
func RoundScore(score float64) float64 {
	return math.Round(score*scoreRoundFactor) / scoreRoundFactor
}
